// C: LUA_API int lua_load (lua_State *L, lua_Reader reader, void *data,
//                          const char *chunkname, const char *mode)
// PORT NOTE: lua_Reader (void* callback) is replaced by Box<dyn FnMut>; mode
// is &[u8].
pub fn load(
    state: &mut LuaState,
    reader: Box<dyn FnMut() -> Option<Vec<u8>>>,
    chunkname: Option<&[u8]>,
    mode: Option<&[u8]>,
) -> Result<LuaStatus, LuaError> {
    let name = chunkname.unwrap_or(b"?");
    // C: luaZ_init(L, &z, reader, data); status = luaD_protectedparser(L, &z, chunkname, mode);
    let z = crate::zio::ZIO::new(reader);
    let status = state.protected_parser(z, name, mode);
    if status == LuaStatus::Ok {
        // C: LClosure *f = clLvalue(s2v(L->top.p - 1));
        // C: if (f->nupvalues >= 1) { set global table as 1st upvalue }
        let top = state.top_idx();
        let func_val = state.get_at(top - 1);
        if let LuaValue::Function(LuaClosure::Lua(lcl)) = func_val {
            if !lcl.upvals.is_empty() {
                // C: const TValue *gt = getGtable(L); setobj(L, f->upvals[0]->v.p, gt);
                let gt = get_global_table(state);
                lcl.set_upval(0, GcRef::new(UpVal::closed(gt)));
            }
        }
    }
    Ok(status)
}

// C: LUA_API int lua_dump (lua_State *L, lua_Writer writer, void *data, int strip)
pub fn dump(
    state: &LuaState,
    writer: &mut dyn FnMut(&[u8]) -> Result<(), LuaError>,
    strip: bool,
) -> Result<bool, LuaError> {
    // C: api_checknelems(L, 1); o = s2v(L->top.p - 1);
    let top = state.top_idx();
    let o = state.get_at(top - 1);
    // C: if (isLfunction(o)) status = luaU_dump(L, getproto(o), writer, data, strip);
    if let LuaValue::Function(LuaClosure::Lua(ref lcl)) = o {
        state.dump_proto(&lcl.proto, writer, strip)?;
        Ok(true)
    } else {
        Ok(false)
    }
}

// C: LUA_API int lua_status (lua_State *L)
pub fn status(state: &LuaState) -> LuaStatus {

/// Loads and parses a chunk in protected mode, returning the status.
///
/// C: `int luaD_protectedparser(lua_State *L, ZIO *z, const char *name, const char *mode)`
pub(crate) fn protected_parser(
    state: &mut LuaState,
    z: ZIO,
    name: &[u8],
    mode: Option<&[u8]>,
) -> LuaStatus {
    // C: incnny(L)  — cannot yield during parsing
    // incnny → state.inc_nny()  (macros.tsv)
    state.inc_nny();

    let mut p = SParser {
        z,
        buff: LexBuffer::new(),
        dyd: DynDataStub::new(),
        mode: mode.map(|m| m.to_vec()),
        name: name.to_vec(),
    };

    // C: luaZ_initbuffer(L, &p.buff) — LexBuffer::new() already initialised above
    // (macros.tsv: luaZ_initbuffer → buf.init() / Mbuffer::new())

    // C: status = luaD_pcall(L, f_parser, &p, savestack(L, L->top.p), L->errfunc)
    let top_idx = state.top_idx();
    let errfunc = state.errfunc;
    let status = pcall(state, |s| f_parser(s, &mut p), top_idx, errfunc);

    // C: luaZ_freebuffer(L, &p.buff) — Rust's Drop handles deallocation (macros.tsv)
    // C: luaM_freearray(L, p.dyd.actvar.arr, ...) — Rust's Drop handles Vec (macros.tsv)
    // (p and all its sub-fields drop here automatically)

    // C: decnny(L)
    // decnny → state.dec_nny()  (macros.tsv)
    state.dec_nny();

    status
}

